CREATE VIEW `ads_sensors_cd_video_operationpositionexposure_big_dipper_view` (`dt` COMMENT "日期", `id` COMMENT "主键", `rid` COMMENT "记录ID", `track_id` COMMENT "track_id", `event` COMMENT "事件", `event_tm` COMMENT "事件时间", `app_channel` COMMENT "渠道编号", `app_id` COMMENT "app_id", `app_lang_id` COMMENT "界面语言", `device_lang` COMMENT "设备语言", `login_id` COMMENT "用户ID", `product_id` COMMENT "产品ID", `app_version` COMMENT "应用版本", `os` COMMENT "操作系统", `core` COMMENT "core版本，目前有1，2，3", `current_language2` COMMENT "注册时语言", `ip` COMMENT "IP", `city` COMMENT "城市", `province` COMMENT "省份", `country` COMMENT "国家", `lib` COMMENT "lib", `page_id` COMMENT "页面ID", `page_name` COMMENT "页面名称", `element_id` COMMENT "控件ID", `element_type` COMMENT "控件类型", `element_name` COMMENT "控件名称", `element_content` COMMENT "元素内容", `activity_id` COMMENT "活动id", `event_strategy_id` COMMENT "策略id", `group_id` COMMENT "用户分组id", `project_id` COMMENT "5阅读 8 短剧", `activity_link` COMMENT "活动链路", `etl_tm` COMMENT "清洗时间") AS SELECT `ods_log`.`a`.`dt`, `ods_log`.`a`.`id`, `ods_log`.`a`.`rid`, `ods_log`.`a`.`track_id`, `ods_log`.`a`.`event`, `ods_log`.`a`.`event_tm`, `ods_log`.`a`.`app_channel`, `ods_log`.`a`.`app_id`, `ods_log`.`a`.`app_lang_id`, `ods_log`.`a`.`device_lang`, `ods_log`.`a`.`login_id`, `ods_log`.`a`.`product_id`, `ods_log`.`a`.`app_version`, `ods_log`.`a`.`os`, CAST((substring(`ods_log`.`a`.`app_id`, 4, 3)) AS INT) AS `core`, `ods`.`b`.`CurrentLanguage2` AS `current_language2`, `ods_log`.`a`.`ip`, `ods_log`.`a`.`city`, `ods_log`.`a`.`province`, `ods_log`.`a`.`country`, `ods_log`.`a`.`lib`, `ods_log`.`a`.`page_id`, `ods_log`.`a`.`page_name`, `ods_log`.`a`.`element_id`, `ods_log`.`a`.`element_type`, `ods_log`.`a`.`element_name`, `ods_log`.`a`.`element_content`, `ods_log`.`a`.`activity_id`, `ods_log`.`a`.`event_strategy_id`, `ods_log`.`a`.`group_id`, `ods_log`.`a`.`project_id`, `ods_log`.`a`.`activity_link`, `ods_log`.`a`.`etl_tm`
FROM `ods_log`.`ods_sensors_cd_video_production_operationpositionexposure_big_dipper` AS `a` LEFT OUTER JOIN `ods`.`ods_tidb_short_video_accountinfo` AS `b` ON `ods_log`.`a`.`login_id` = `ods`.`b`.`Id`
WHERE `ods_log`.`a`.`project_id` = '8';